import json

# Debug: Check what variables are available in local scope
vars_in_scope = list(locals().keys())
print(f"Variables in scope: {len(vars_in_scope)}")

# Let's look for our data structures
nyse_data = None
trade_symbols_list = None

for var_name in vars_in_scope:
    var_value = locals()[var_name]
    if isinstance(var_value, list) and len(var_value) > 0:
        if isinstance(var_value[0], dict) and 'Symbol' in var_value[0]:
            nyse_data = var_value
            print(f"Found NYSE data: {len(nyse_data)} records in variable {var_name}")
        elif isinstance(var_value[0], str):
            trade_symbols_list = var_value
            print(f"Found trade symbols: {len(trade_symbols_list)} records in variable {var_name}")

# If we didn't find them in direct variables, they might be stored as file paths
if nyse_data is None:
    # Try to find file path variables
    for var_name in vars_in_scope:
        if 'query_db' in var_name and 'stockinfo' in str(locals()[var_name]):
            file_path = locals()[var_name]
            try:
                with open(file_path, 'r') as f:
                    nyse_data = json.load(f)
                print(f"Loaded NYSE data from file: {len(nyse_data)} records")
            except:
                pass

if trade_symbols_list is None:
    for var_name in vars_in_scope:
        if 'list_db' in var_name:
            file_path = locals()[var_name]
            try:
                with open(file_path, 'r') as f:
                    trade_symbols_list = json.load(f)
                print(f"Loaded trade symbols from file: {len(trade_symbols_list)} records")
            except:
                pass

# Now process the data
if nyse_data and trade_symbols_list:
    # Create mappings
    symbol_to_company = {item['Symbol']: item['Company Description'] for item in nyse_data}
    nyse_symbols = set(symbol_to_company.keys())
    available_symbols = sorted(list(nyse_symbols.intersection(set(trade_symbols_list))))

    print(f"Total NYSE non-ETF stocks: {len(nyse_symbols)}")
    print(f"Available with trade data: {len(available_symbols)}")
    print(f"Sample: {available_symbols[:10]}")

    # Save for next steps
    result_data = {
        'available_symbols': available_symbols,
        'symbol_to_company': symbol_to_company,
        'count': len(available_symbols)
    }

    with open('nyse_analysis_data.json', 'w') as f:
        json.dump(result_data, f)

    final_result = {
        'status': 'success',
        'available_symbols_count': len(available_symbols),
        'sample_symbols': available_symbols[:5]
    }
else:
    final_result = {
        'status': 'failed',
        'message': 'Missing required data'
    }

print('__RESULT__:')
print(json.dumps(final_result))

