import json

# Find the NYSE data and trade symbols in locals()
nyse_data = None
trade_symbols_list = None

for key in locals().keys():
    value = locals()[key]
    if isinstance(value, list) and len(value) > 0:
        if isinstance(value[0], dict) and 'Symbol' in value[0] and 'Company Description' in value[0]:
            nyse_data = value
            print(f"Found NYSE data: {len(nyse_data)} records")
        elif isinstance(value[0], str) and len(value) > 100:
            trade_symbols_list = value
            print(f"Found trade symbols: {len(trade_symbols_list)} symbols")

# Process the data
if nyse_data and trade_symbols_list:
    # Create symbol to company mapping
    symbol_to_company = {}
    for stock in nyse_data:
        symbol_to_company[stock['Symbol']] = stock['Company Description']

    nyse_symbols = set(symbol_to_company.keys())
    available_symbols = sorted(list(nyse_symbols.intersection(set(trade_symbols_list))))

    print(f"Available NYSE stocks: {len(available_symbols)}")
    print(f"Sample: {available_symbols[:10]}")

    # Save for analysis
    result = {
        'symbol_to_company': symbol_to_company,
        'available_symbols': available_symbols,
        'count': len(available_symbols)
    }

    with open('nyse_data.json', 'w') as f:
        json.dump(result, f)

else:
    print("Missing data - using fallback")
    result = {'error': 'missing_data'}

print('__RESULT__:')
print(json.dumps(result))

